import random
import time
import threading

class Lift:
    def __init__(self, id, floors):
        self.id = id
        self.floors = floors
        self.current_floor = 1
        self.direction = 1
        self.passengers = 0

    def move(self):
        if self.direction == 1 and self.current_floor < self.floors:
            self.current_floor += 1
        elif self.direction == -1 and self.current_floor > 1:
            self.current_floor -= 1
        if self.current_floor == self.floors or self.current_floor == 1:
            self.direction *= -1

    def pick_up(self):
        if random.random() < 0.5:
            self.passengers += 1
            print(f"Lift {self.id} picked up a passenger at floor {self.current_floor}")

    def drop_off(self):
        if self.passengers > 0 and random.random() < 0.5:
            self.passengers -= 1
            print(f"Lift {self.id} dropped off a passenger at floor {self.current_floor}")

class Building:
    def __init__(self, num_floors, num_lifts):
        self.num_floors = num_floors
        self.num_lifts = num_lifts
        self.lifts = [Lift(i, num_floors) for i in range(1, num_lifts + 1)]

    def simulate(self, crowd_size, hour):
        for lift in self.lifts:
            lift.move()
            if crowd_size > 0 and random.random() < crowd_size / 100:
                lift.pick_up()
            if crowd_size > 0 and random.random() < crowd_size / 100:
                lift.drop_off()
        print(f"Hour {hour}: Lifts are currently at floors {[lift.current_floor for lift in self.lifts]}")

def simulate_day(building, crowd_sizes):
    for hour in range(24):
        crowd_size = crowd_sizes[hour % len(crowd_sizes)]
        building.simulate(crowd_size, hour)
        time.sleep(0.1)

def main():
    num_floors = 20
    num_lifts = 5
    crowd_sizes = [50, 50, 50, 50, 50, 20, 20, 20, 20, 20, 10, 10, 10, 10, 10, 5, 5, 5, 5, 5, 5, 5, 5, 5]
    building = Building(num_floors, num_lifts)
    simulate_day(building, crowd_sizes)

if __name__ == "__main__":
