import random
import time

class Lift:
    def __init__(self, id):
        self.id = id
        self.current_floor = 1
        self.direction = 0  # 0: idle, 1: up, -1: down
        self.passengers = 0

    def move(self):
        if self.direction == 1:
            self.current_floor += 1
        elif self.direction == -1:
            self.current_floor -= 1

    def __str__(self):
        return f"Lift {self.id} at floor {self.current_floor} with {self.passengers} passengers"

class Building:
    def __init__(self, num_floors, num_lifts):
        self.num_floors = num_floors
        self.num_lifts = num_lifts
        self.lifts = [Lift(i) for i in range(1, num_lifts + 1)]

    def simulate(self, crowd_size, hours):
        for hour in range(hours):
            print(f"Hour {hour+1}:")
            for minute in range(60):
                if hour < 8 or hour > 16:  # night or evening
                    if random.random() < 0.1 * crowd_size / 100:  # 10% chance of a person arriving
                        self.arrive()
                elif hour < 12:  # morning
                    if random.random() < 0.5 * crowd_size / 100:  # 50% chance of a person arriving
                        self.arrive()
                else:  # afternoon
                    if random.random() < 0.2 * crowd_size / 100:  # 20% chance of a person arriving
                        self.arrive()
                self.update_lifts()
                time.sleep(0.1)  # simulate 1 minute
            print()

    def arrive(self):
        lift = random.choice(self.lifts)
        if lift.passengers < 10:  # assume max 10 passengers per lift
            lift.passengers += 1
            print(f"Person arrived at lift {lift.id}")

    def update_lifts(self):
        for lift in self.lifts:
            if lift.passengers > 0:
                if lift.current_floor < self.num_floors:
                    lift.direction = 1
                else:
                    lift.direction = -1
            else:
                lift.direction = 0
            lift.move()
            if lift.direction != 0 and random.random() < 0.1:  # 10% chance of a person leaving
                lift.passengers -= 1
                print(f"Person left lift {lift.id}")
            print(lift)

