            for lift in self.lifts:
                lift.passengers = 0
            for _ in range(crowd_size):
                if hour < 8 or hour > 16:
                    if random.random() < 0.5:
                        self.call_lift(random.randint(1, self.num_floors))
                elif hour < 12:
