import matplotlib.pyplot as plt

class Lift:
    def __init__(self, id, num_floors):
        self.id = id
        self.num_floors = num_floors
        self.current_floor = 1
        self.direction = 0  # 1 for up, -1 for down, 0 for idle
        self.passengers = 0

    def move(self):
        if self.direction == 1:
            self.current_floor += 1
            if self.current_floor > self.num_floors:
                self.direction = -1
        elif self.direction == -1:
            self.current_floor -= 1
            if self.current_floor < 1:
                self.direction = 1

    def pick_up(self):
        self.passengers += 1

    def drop_off(self):
        self.passengers -= 1

class Building:
    def __init__(self, num_floors, num_lifts):
        self.num_floors = num_floors
        self.num_lifts = num_lifts
        self.lifts = [Lift(i, num_floors) for i in range(num_lifts)]
        self.crowd_size = 0
        self.hour = 0
        self.usage = {i: 0 for i in range(24)}

    def simulate_hour(self):
        self.hour += 1
        if self.hour > 23:
            self.hour = 0
        if self.hour < 8 or self.hour > 17:
            self.crowd_size = random.randint(0, 10)
        elif self.hour < 9 or self.hour > 16:
            self.crowd_size = random.randint(50, 100)
        else:
            self.crowd_size = random.randint(10, 50)
        for lift in self.lifts:
            if lift.passengers > 0:
                lift.move()
                if lift.current_floor == random.randint(1, self.num_floors):
                    lift.drop_off()
            elif self.crowd_size > 0:
                lift.pick_up()
                self.crowd_size -= 1
                lift.direction = 1 if random.random() < 0.5 else -1
        self.usage[self.hour] += sum([lift.passengers for lift in self.lifts])

    def run_simulation(self, hours):
        for _ in range(hours):
            self.simulate_hour()
        plt.bar(self.usage.keys(), self.usage.values())
