class Lift:
    def __init__(self, id):
        self.id = id
        self.current_floor = 1
        self.direction = 0  # 1 for up, -1 for down, 0 for idle
        self.passengers = 0

    def move(self):
        if self.direction == 1:
            self.current_floor += 1
        elif self.direction == -1:
            self.current_floor -= 1

    def update(self, time_of_day, num_floors):
        if time_of_day < 8 or time_of_day > 17:
            if random.random() < 0.1:
                self.direction = 1 if random.random() < 0.5 else -1
        elif time_of_day < 12:
            if random.random() < 0.5:
                self.direction = 1 if random.random() < 0.7 else -1
        elif time_of_day < 14:
            if random.random() < 0.2:
                self.direction = 1 if random.random() < 0.5 else -1
        else:
            if random.random() < 0.5:
                self.direction = 1 if random.random() < 0.3 else -1

        if self.current_floor == 1 and self.direction == -1:
            self.direction = 0
        elif self.current_floor == num_floors and self.direction == 1:
            self.direction = 0

        if self.direction != 0:
            self.move()

    def __str__(self):
        return f'Lift {self.id} at floor {self.current_floor} with {self.passengers} passengers'

class Building:
    def __init__(self, num_floors, num_lifts):
        self.num_floors = num_floors
        self.num_lifts = num_lifts
        self.lifts = [Lift(i) for i in range(num_lifts)]

    def simulate(self, time_of_day, crowd_size):
        for lift in self.lifts:
            lift.update(time_of_day, self.num_floors)
            if random.random() < crowd_size / 100:
                lift.passengers += 1
            if lift.passengers > 0 and random.random() < 0.2:
                lift.passengers -= 1

    def __str__(self):
        return '\n'.join([str(lift) for lift in self.lifts])

