class Occupant:
    def __init__(self, id):
        self.id = id
        self.current_floor = random.randint(1, 10)
        self.destination_floor = random.randint(1, 10)

    def move(self, elevators):
        if self.current_floor == self.destination_floor:
            self.destination_floor = random.randint(1, 10)
        closest_elevator = min(elevators, key=lambda x: abs(x.current_floor - self.current_floor))
