import calendar
from datetime import datetime, timedelta

def get_normalized_time(now=None):
    if now is None:
        now = datetime.now()
    return now.replace(hour=0, minute=0, second=0, microsecond=0)

def calculate_day_length(now=None):
    if now is None:
        now = datetime.now()
    normalized_time = get_normalized_time(now)
    next_day = normalized_time + timedelta(days=1)
    return (next_day - normalized_time).seconds

def get_current_day(now=None):
    if now is None:
        now = datetime.now()
    return calendar.day_name[now.weekday()]

def get_start_of_day(now=None):
    if now is None:
        now = datetime.now()
    return get_normalized_time(now)

