def decode_text(text):
    decoded_text = ""
    for char in text:
        if char.isalpha():
            if char.islower():
                decoded_text += chr((ord(char) - 97 - 3) % 26 + 97)
            else:
                decoded_text += chr((ord(char) - 65 - 3) % 26 + 65)
        else:
            decoded_text += char
    return decoded_text

