import datetime
import random

class Person:
    def __init__(self, name, age):
        self.name = name
        self.age = age

    def __str__(self):
        return f"{self.name} is {self.age} years old"

class Student(Person):
    def __init__(self, name, age, grade):
        super().__init__(name, age)
        self.grade = grade

    def __str__(self):
        return f"{self.name} is {self.age} years old and in grade {self.grade}"

class Teacher(Person):
    def __init__(self, name, age, subject):
        super().__init__(name, age)
        self.subject = subject

    def __str__(self):
        return f"{self.name} is {self.age} years old and teaches {self.subject}"

def generate_random_person():
    names = ["John", "Alice", "Bob", "Eve", "Mike"]
    ages = [20, 25, 30, 35, 40]
    return Person(random.choice(names), random.choice(ages))

