    names = ["John", "Alice", "Bob", "Eve", "Mike"]
    ages = [25, 30, 35, 40, 45]
    subjects = ["Math", "Science", "English", "History", "Geography"]
    return Teacher(random.choice(names), random.choice(ages), random.choice(subjects))

